#include <iostream>

using namespace std;

int hammingWeight(unsigned int n)
{
    int count = 0;
    while (n != 0)
    {
        n &= (n - 1); // clear the lowest set bit
        count++;
    }
    return count;
}

int main()
{
    cout << hammingWeight(11);

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

int countBits(int n)
{
    int count = 0;
    while (n > 0)
    {
        count += (n & 1);
        n >>= 1;
    }
    return count;
}

vector<int> countBitsArray(int n)
{
    vector<int> result(n + 1);
    for (int i = 0; i <= n; i++) result[i] = countBits(i);
    return result;
}

int main()
{
    vector<int> result = countBitsArray(5);
    for (int r : result) cout << r << " ";

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

vector<int> countBitsArray(int n)
{
    vector<int> dp(n + 1, 0);
    for (int i = 1; i <= n; i++)
        dp[i] = dp[i >> 1] + (i & 1);
    return dp;
}

int main()
{
    vector<int> result = countBitsArray(5);
    for (int r : result) cout << r << " ";

    return 0;
}

